rss.channel:

            {{ config.title }}
            {%- if term %} - {{ term.name }}
            {%- elif section.title %} - {{ section.title }}
            {%- endif -%}


            {%- if section -%}
                {{ section.permalink | escape_xml | safe }}
            {%- else -%}
                {{ config.base_url | escape_xml | safe }}
            {%- endif -%}

        {{ config.description }}
        Zola
        {{ lang }}


    {% if last_updated is defined %}
        {{ last_updated | date(format="%a, %d %b %Y %H:%M:%S %z") }}
    {% endif %}

    {%- for page in pages %}


            {{ page.title | escape_xml }}
            {{ page.date | date(format="%a, %d %b %Y %H:%M:%S %z") }}
            {{ page.permalink | escape_xml | safe }}
            {{ page.permalink | escape_xml | safe }}

            {{ page.summary | default(value=page.title) }}


				{#
					first replace transforms internal links to permalink.
					second one replaces relative link to parent path. it only does 1 level.
				#}
				{% set base = page.components | slice(end=-1) | join(sep='/') %}
                {{
                    page.content
                        | replace(from='href="#', to='href="' ~ page.permalink ~ '#')
                        | replace(from='href="../', to='href="' ~ config.base_url ~ '/' ~ base ~ '/')
                        | safe
                }}


    {%- endfor %}
